insert into questions (id, level_id, type, question_text, image_url, explanation, points)
values
  ('10000000-0000-0000-0000-000000000001', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'Les glucides sont des molécules organiques définies comme :', null, 'Les glucides sont des molécules organiques possédant des fonctions alcools (–OH) et une fonction carbonylique réductrice (aldéhyde ou cétone). Formule générale : (CH₂O)n.', 1),
  ('10000000-0000-0000-0000-000000000002', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'L''oxydation complète d''une molécule de glucose produit :', null, 'L''oxydation complète du glucose par la glycolyse + cycle de Krebs + phosphorylation oxydative produit environ 38 ATP, soit ≈ 380 kcal/mol. Le glucose est le carburant principal des cellules.', 1),
  ('10000000-0000-0000-0000-000000000003', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'Un ose possédant 5 atomes de carbone est appelé :', null, 'La nomenclature est basée sur le nombre de carbones : 3C = triose, 4C = tétrose, 5C = pentose, 6C = hexose. Le D-ribose et le D-désoxyribose sont les pentoses les plus importants biologiquement (ARN, ADN).', 1),
  ('10000000-0000-0000-0000-000000000004', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'Quelle est la différence entre un aldose et un cétose ?', null, 'Les aldoses possèdent une fonction aldéhyde (CHO) en C1 (ex. glucose), tandis que les cétoses possèdent une fonction cétone (C=O) en C2 (ex. fructose).', 1),
  ('10000000-0000-0000-0000-000000000005', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'Le D-glucose et le D-galactose sont des :', null, 'Le D-glucose et le D-galactose ne diffèrent que par la configuration du carbone 4 → ce sont des épimères en C4. Les épimères ne diffèrent que par la configuration d''un seul carbone asymétrique.', 1),
  ('10000000-0000-0000-0000-000000000006', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'Dans la convention de Fischer, la série D ou L est définie par :', null, 'La série D ou L est déterminée par la configuration du C* le plus proche du CH₂OH (le dernier C asymétrique dans la chaîne de Fischer). D = OH à droite, L = OH à gauche. La plupart des glucides biologiques sont de série D.', 1),
  ('10000000-0000-0000-0000-000000000007', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'Le phénomène de mutarotation du glucose aboutit à une valeur stable de :', null, 'La mutarotation correspond à l''équilibre entre les anomères α (PR = +112,2°) et β (PR = +18,7°) du D-glucose en solution. La valeur stable à l''équilibre est +52,7°, caractéristique du mélange des deux anomères.', 1),
  ('10000000-0000-0000-0000-000000000008', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'La cyclisation du D-glucose selon Tollens forme un pont oxydique entre :', null, 'Le D-glucose cyclise préférentiellement entre C1 et C5, formant un cycle à 6 chaînons (1O + 5C) analogue au pyrane → glucopyranose. La cyclisation C1-C4 formerait un furanose (cycle à 5 chaînons).', 1),
  ('10000000-0000-0000-0000-000000000009', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'En représentation de Haworth, l''anomère α-D-glucose se caractérise par :', null, 'En représentation de Haworth : anomère α = OH du C1 en position trans par rapport au CH₂OH (vers le bas). Anomère β = OH du C1 en position cis (vers le haut). En Fischer : α = OH du C1 du même côté que le dernier OH.', 1),
  ('10000000-0000-0000-0000-000000000010', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'La liqueur de Fehling permet de détecter les oses réducteurs car elle :', null, 'Les oses réducteurs (OH anomérique libre) réduisent les ions Cu²⁺ de la liqueur de Fehling en Cu⁺, formant un précipité rouge brique de Cu₂O. Les osides non réducteurs (ex. saccharose) ne réagissent pas.', 1),
  ('10000000-0000-0000-0000-000000000011', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'Les désoxyoses sont des oses qui ont :', null, 'Les désoxyoses ont perdu un atome d''oxygène : un –OH est remplacé par –H. Exemples : le 2-désoxyribose (OH en C2 → H, constituant de l''ADN) et le L-fucose (désoxyose en C6 du galactose).', 1),
  ('10000000-0000-0000-0000-000000000012', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'L''acide D-glucuronique est obtenu à partir du D-glucose par :', null, 'Les acides uroniques sont produits par l''oxydation sélective de la fonction alcool primaire (C6) en –COOH par KMnO₄, après blocage de la fonction carbonyle. L''acide glucuronique est un constituant des glycosaminoglycanes.', 1),
  ('10000000-0000-0000-0000-000000000013', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'La liaison osidique est rompue par :', null, 'La liaison osidique peut être rompue par : (1) voie chimique : HCl dilué à chaud, ou (2) voie enzymatique : glycosidases (osidases) spécifiques à l''ose et à l''anomérie (ex. α-glucosidase, β-galactosidase).', 1),
  ('10000000-0000-0000-0000-000000000014', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'La cellulose, constituant structural des végétaux, est composée de :', null, 'La cellulose est un polymère linéaire de D-glucose en liaisons β(1→4). Ces liaisons β permettent des interactions entre chaînes par liaisons hydrogène, conférant rigidité et résistance à la paroi végétale. L''humain ne peut pas la digérer (pas de β-glucosidase intestinale).', 1),
  ('10000000-0000-0000-0000-000000000015', '11111111-2222-3333-4444-000000000001', 'qcm_single', 'La synthèse de Kiliani permet d''obtenir :', null, 'La synthèse de Kiliani allonge la chaîne carbonée d''un carbone, partant du D-glycéraldéhyde pour obtenir les aldoses supérieurs (tétrose → pentose → hexose) en 3 étapes : addition de HCN, hydratation, réduction. Elle conserve le C* initial intact.', 1),
  ('10000000-0000-0000-0000-000000000016', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez le D-Glucose en représentation de Fischer — aldohexose, CHO en C1, OH à droite en C5 (série D) :', null, 'Le D-glucose est un aldohexose : CHO en C1, puis H–C–OH / HO–C–H / H–C–OH / H–C–OH (OH à droite en C5 = série D). C''est l''ose le plus abondant, combustible universel des cellules, PR = +52,7°.', 1),
  ('10000000-0000-0000-0000-000000000017', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez le D-Fructose — cétohexose avec C=O en C2 et CH₂OH en C1 :', null, 'Le D-fructose (lévulose) est un cétohexose : CH₂OH en C1, C=O en C2, puis chaîne d''alcools. PR = −93° (lévogyre). Très abondant dans les fruits et le miel. Isomère de fonction du glucose.', 1),
  ('10000000-0000-0000-0000-000000000018', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez le D-Ribose — aldopentose à 5 carbones, tous les OH à droite :', null, 'Le D-ribose est un aldopentose (5C) : CHO en C1, tous les OH à droite, CH₂OH en C5 (série D). Il entre dans la structure des acides nucléiques (ARN) et de nombreuses coenzymes (NAD, FAD, ATP).', 1),
  ('10000000-0000-0000-0000-000000000019', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez le D-Galactose — épimère du glucose en C4 (OH en C4 à gauche dans Fischer) :', null, 'Le D-galactose est l''épimère du glucose en C4 : OH en C4 est à gauche (HO–C–H) dans la projection de Fischer. PR = +80°. Peu répandu à l''état libre, très abondant dans les osides (lactose) et les lipides complexes.', 1),
  ('10000000-0000-0000-0000-000000000020', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez l''α-D-glucopyranose en représentation de Haworth — OH en C1 trans par rapport à CH₂OH :', null, 'L''α-D-glucopyranose : le OH du C1 est en position trans (opposée) par rapport au CH₂OH dans la représentation de Haworth (vers le bas). PR = +112,2°. Le préfixe ''pyranose'' indique le cycle à 6 chaînons (analogue au pyrane).', 1),
  ('10000000-0000-0000-0000-000000000021', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez le β-D-glucopyranose — OH en C1 cis par rapport à CH₂OH :', null, 'Le β-D-glucopyranose : le OH du C1 est en position cis par rapport au CH₂OH dans Haworth (vers le haut). PR = +18,7°. Forme la plus stable (tous les substituants en position équatoriale dans la conformation chaise). Constituant de la cellulose.', 1),
  ('10000000-0000-0000-0000-000000000022', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez l''α-D-fructofuranose — cycle à 5 chaînons (pont oxydique C2–C5) :', null, 'Le D-fructofuranose se forme par un pont oxydique entre C2 et C5, donnant un cycle à 5 chaînons (1O + 4C), analogue au furane. Dans le saccharose, le fructose est sous forme β-D-fructofuranose.', 1),
  ('10000000-0000-0000-0000-000000000023', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez le Maltose — diholoside réducteur formé de 2 glucoses en α(1→4) :', null, 'Le maltose est un diholoside réducteur (OH anomérique libre sur le 2e glucose) composé de 2 D-glucose en liaison α(1→4). Produit intermédiaire de l''hydrolyse de l''amidon et du glycogène. Absent à l''état libre.', 1),
  ('10000000-0000-0000-0000-000000000024', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez le Saccharose — diholoside NON réducteur, liaison α(1→2)β entre glucose et fructose :', null, 'Le saccharose (sucre de table) est non réducteur car la liaison α(1→2)β engage les deux OH anomériques (C1 du glucose et C2 du fructose). Il ne réagit donc pas avec la liqueur de Fehling. Hydrolysé par la saccharase/invertase.', 1),
  ('10000000-0000-0000-0000-000000000025', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez le Lactose — sucre du lait, β(1→4) entre galactose et glucose :', null, 'Le lactose (sucre du lait) est formé de β-D-galactose et D-glucose en liaison β(1→4). Réducteur (OH anomérique du glucose libre). Hydrolysé par la β-galactosidase (lactase). Intolérance = déficit en lactase.', 1),
  ('10000000-0000-0000-0000-000000000026', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez l''Amylose — fraction de l''amidon à chaîne linéaire α(1→4) :', null, 'L''amylose est la fraction linéaire de l''amidon : chaîne de D-glucose en liaisons α(1→4), prenant une conformation hélicoïdale. Se colore en bleu-violet avec l''iode. La fraction ramifiée est l''amylopectine (α1→4 + α1→6).', 1),
  ('10000000-0000-0000-0000-000000000027', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez la Cellulose — polymère structurel végétal à liaisons β(1→4) rigides :', null, 'La cellulose est un polymère linéaire de D-glucose en liaisons β(1→4). Ces liaisons permettent la formation de liaisons hydrogène inter-chaînes, donnant une structure fibreuse très résistante (paroi végétale). Non digestible par l''humain.', 1),
  ('10000000-0000-0000-0000-000000000028', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez l''Acide D-Glucuronique — ose avec COOH en C6 au lieu de CH₂OH :', null, 'L''acide D-glucuronique est dérivé du glucose par oxydation sélective du CH₂OH (C6) en –COO⁻ par KMnO₄. Il entre dans la composition des glycosaminoglycanes (acide hyaluronique, héparane sulfate…).', 1),
  ('10000000-0000-0000-0000-000000000029', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez la D-Glucosamine — ose aminé avec NH₂ en C2 :', null, 'La D-glucosamine est un ose aminé : le OH en C2 est remplacé par un groupement –NH₂. Souvent acétylée (N-acétyl-glucosamine), c''est un constituant majeur des glycoprotéines et des glycosaminoglycanes (chitine, héparane sulfate).', 1),
  ('10000000-0000-0000-0000-000000000030', '11111111-2222-3333-4444-000000000002', 'qcm_single', 'Identifiez le 2-Désoxyribose — pentose de l''ADN, OH en C2 remplacé par H :', null, 'Le 2-désoxyribose est le pentose constitutif de l''ADN : le OH en C2 est remplacé par un atome d''hydrogène (d''où ''désoxy''). Ceci rend l''ADN plus stable chimiquement que l''ARN (qui utilise le ribose avec un OH en C2).', 1),
  ('10000000-0000-0000-0000-000000000031', '11111111-2222-3333-4444-000000000003', 'qcm_single', 'Le saccharose, le maltose et le lactose appartiennent à la catégorie des :', null, 'Le saccharose, le maltose et le lactose sont des diholosides, donc des oligosides (2–10 unités d''oses liées). Les oligosides sont des holosides (uniquement des oses) hydrolysables. Les polyosides ont >10 unités.', 1),
  ('10000000-0000-0000-0000-000000000032', '11111111-2222-3333-4444-000000000003', 'qcm_single', 'Le D-glucose, le D-galactose et le D-mannose sont tous des :', null, 'Le glucose, le galactose et le mannose sont des aldohexoses : 6 carbones (hexose) avec une fonction carbonylique de type aldéhyde (CHO) en C1. Ce sont des stéréoisomères (même formule brute C₆H₁₂O₆, mais configurations différentes).', 1),
  ('10000000-0000-0000-0000-000000000033', '11111111-2222-3333-4444-000000000003', 'qcm_single', 'Parmi ces glucides, lequel N''EST PAS réducteur ?', null, 'Le saccharose est non réducteur car la liaison α(1→2)β engage les deux carbones anomériques (C1 du glucose et C2 du fructose) → aucun OH anomérique libre → ne peut pas passer en forme ouverte → ne réagit pas avec Fehling. Les autres ont un OH anomérique libre.', 1),
  ('10000000-0000-0000-0000-000000000034', '11111111-2222-3333-4444-000000000003', 'qcm_single', 'L''amidon (chez les végétaux) et le glycogène (chez les animaux) sont tous deux des :', null, 'L''amidon et le glycogène sont tous deux des homopolysaccharides de D-glucose avec des liaisons α(1→4) en chaîne principale et des branchements α(1→6). Le glycogène est plus ramifié que l''amylopectine. Ce sont les formes de réserve glucidique.', 1),
  ('10000000-0000-0000-0000-000000000035', '11111111-2222-3333-4444-000000000003', 'qcm_single', 'La cellulose (végétaux) et la chitine (arthropodes) jouent principalement un rôle :', null, 'La cellulose (paroi végétale) et la chitine (exosquelette des arthropodes, paroi des champignons) jouent un rôle structural. La chitine est composée de N-acétyl-glucosamine en liaisons β(1→4). Ces polysaccharides confèrent rigidité et résistance.', 1),
  ('10000000-0000-0000-0000-000000000036', '11111111-2222-3333-4444-000000000003', 'qcm_single', 'L''oxydation douce du D-glucose par Br₂ (ou I₂) produit :', null, 'L''oxydation douce par Br₂ ou I₂ oxyde sélectivement la fonction aldéhyde (C1) en –COOH → acide D-gluconique (acide aldonique). L''oxydation forte par HNO₃ oxyde en plus l''alcool primaire (C6) → acide aldarique (acide glucarique).', 1),
  ('10000000-0000-0000-0000-000000000037', '11111111-2222-3333-4444-000000000003', 'qcm_single', 'La réduction du D-glucose par NaBH₄ (ou LiBH₄) donne :', null, 'La réduction de la fonction aldéhyde du D-glucose par NaBH₄ ou LiBH₄ produit le D-sorbitol (alcool I°, polyalcool). La réduction du D-fructose donne un mélange de D-sorbitol et de D-mannitol (car un nouveau C* est créé en C2).', 1),
  ('10000000-0000-0000-0000-000000000038', '11111111-2222-3333-4444-000000000003', 'qcm_single', 'L''acide hyaluronique et l''héparine sont des exemples de :', null, 'L''acide hyaluronique et l''héparine sont des glycosaminoglycanes (GAG) : ce sont des polysaccharides hétérogènes formés par polycondensation alternée d''osamines (N-acétyl-glucosamine…) et d''acides uroniques (acide glucuronique…).', 1),
  ('10000000-0000-0000-0000-000000000039', '11111111-2222-3333-4444-000000000003', 'qcm_single', 'L''acide périodique (HIO₄) est un oxydant puissant qui :', null, 'L''acide périodique (HIO₄) coupe de façon spécifique la liaison C–C entre deux carbones adjacents porteurs de –OH libres (1,2-diol). Il libère des aldéhydes, de l''acide formique (–CH₂OH terminal), et permet de déterminer la structure des oses cycliques.', 1),
  ('10000000-0000-0000-0000-000000000040', '11111111-2222-3333-4444-000000000003', 'qcm_single', 'Le D-galactose et le L-galactose sont des :', null, 'Le D-galactose et le L-galactose sont des énantiomères : ils sont images l''un de l''autre dans un miroir et non superposables (comme les mains droite et gauche). Tous leurs C* ont des configurations inversées. Ils ont les mêmes propriétés physico-chimiques mais des pouvoirs rotatoires de signes opposés.', 1),
  ('20000000-0000-0000-0000-000000000001', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'Quelle propriété physique est caractéristique de TOUS les lipides ?', null, 'Les lipides sont des composés apolaires, insolubles dans l''eau mais solubles dans les solvants organiques (éther, chloroforme, benzène, acétone). C''est la propriété physique qui les définit tous.', 1),
  ('20000000-0000-0000-0000-000000000002', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'Parmi ces lipides, lequel appartient aux lipides SIMPLES (homolipides) ?', null, 'Les glycérides (monoglycérides, diglycérides, triglycérides) sont des lipides simples ou homolipides, car leur hydrolyse ne libère que des acides gras et du glycérol. Les glycérophospholipides et sphingolipides sont des lipides composés ou hétérolipides.', 1),
  ('20000000-0000-0000-0000-000000000003', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'Quelle est la formule générale d''un acide gras saturé ?', null, 'Un acide gras saturé répond à la formule CH₃–(CH₂)n–COOH. La chaîne est linéaire, sans double liaison, avec un nombre pair d''atomes de carbone. L''acide gras le plus petit des lipides est l''acide butyrique (C4).', 1),
  ('20000000-0000-0000-0000-000000000004', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'L''acide oléique est un acide gras en C18 avec une double liaison en position 9. Sa notation correcte est :', null, 'L''acide oléique est noté C18:1 Δ9 : 18 carbones, 1 double liaison, en position 9. C''est un acide gras monoinsaturé. Le C18:2 Δ9,12 est l''acide linoléique et le C20:4 est l''acide arachidonique.', 1),
  ('20000000-0000-0000-0000-000000000005', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'Pourquoi l''huile est-elle liquide à température ambiante contrairement au beurre ?', null, 'L''huile est riche en acides gras insaturés (oléique, linoléique). Plus un acide gras est insaturé, plus son point de fusion est bas. Les doubles liaisons créent des coudes dans la chaîne qui empêchent le tassement des molécules, abaissant le point de fusion. Le beurre, riche en AG saturés, est solide.', 1),
  ('20000000-0000-0000-0000-000000000006', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'Qu''est-ce que l''indice de saponification (Is) ?', null, 'L''indice de saponification (Is) est défini comme la quantité en mg de potasse (KOH) qui saponifie 1 g de matière grasse. Il permet de déterminer la masse moléculaire moyenne des acides gras d''un corps gras. Plus les AG sont courts, plus l''Is est élevé.', 1),
  ('20000000-0000-0000-0000-000000000007', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'L''indice d''iode (Ii) permet de mesurer :', null, 'L''indice d''iode (Ii) est la quantité en grammes d''iode fixée par 100 g de matière grasse. Les halogènes (I₂, Br₂) s''additionnent aux doubles liaisons : plus la valeur est élevée, plus le lipide est insaturé. C''est donc un indicateur du degré d''insaturation.', 1),
  ('20000000-0000-0000-0000-000000000008', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'Dans un triglycéride, le carbone Cβ du glycérol est dit ''asymétrique''. Cela signifie :', null, 'Le Cβ du glycérol dans un triglycéride est substitué asymétriquement, ce qui engendre deux isomères possibles (isomère I et isomère II). Chez les organismes vivants, les triglycérides sont de type isomère II.', 1),
  ('20000000-0000-0000-0000-000000000009', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'Dans un glycérophospholipide, comment sont répartis les acides gras dans les organismes vivants ?', null, 'Dans les glycérophospholipides naturels : en Cα se trouve un AG saturé (R1), en Cβ se trouve un AG insaturé (R2), et en Cα'' se trouve l''acide phosphorique lié à un groupement X. Cette disposition est caractéristique des membranes biologiques.', 1),
  ('20000000-0000-0000-0000-000000000010', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'Quelle phospholipase coupe la liaison au niveau du Cβ du glycérophospholipide ?', null, 'La phospholipase A2 coupe spécifiquement la liaison ester au niveau du Cβ, libérant l''acide gras insaturé en position 2. La phospholipase A1 (ou B) coupe en Cα, la phospholipase C coupe entre le glycérol et le phosphate, et la phospholipase D coupe entre le phosphate et le groupement X.', 1),
  ('20000000-0000-0000-0000-000000000011', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'Quelle est la différence fondamentale entre les sphingolipides et les glycérophospholipides ?', null, 'La différence fondamentale : les sphingolipides contiennent de la sphingosine (alcool aminé à longue chaîne) à la place du glycérol. La sphingosine est liée à un AG par une liaison amide (sur la fonction amine) et non par une liaison ester.', 1),
  ('20000000-0000-0000-0000-000000000012', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'Les sphingomyélines sont particulièrement abondantes dans :', null, 'Les sphingomyélines sont abondantes dans les neurones où elles constituent la gaine de myéline. La gaine de myéline isole les axones et permet une transmission rapide de l''influx nerveux.', 1),
  ('20000000-0000-0000-0000-000000000013', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'Un galactocérébroside est composé de :', null, 'Un galactocérébroside est formé d''un céramide lié à une molécule de D-galactose par une liaison β-glycosidique (β D-galactosyl(1;1) céramide). C''est un lipide non phosphoré (sans acide phosphorique). Il est présent dans le tissu nerveux.', 1),
  ('20000000-0000-0000-0000-000000000014', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'Les terpènes sont des lipides insaponifiables formés par polymérisation d''unités :', null, 'Les terpènes sont des lipides insaponifiables formés par polymérisation d''unités d''isoprène (2-méthyl-1,3-butadiène, C5H8). Selon le nombre d''unités : monoterpènes (2 unités, 10C), diterpènes (4 unités, 20C), etc. Exemples : géraniol (géranium), menthol (menthe), carotènes.', 1),
  ('20000000-0000-0000-0000-000000000015', '22222222-3333-4444-5555-000000000001', 'qcm_single', 'La réaction de saponification d''un glycéride en milieu basique (NaOH) produit :', null, 'En milieu basique (NaOH ou KOH), un glycéride subit une saponification pour donner du glycérol et des sels d''acides gras (appelés savons). C''est le principe de la fabrication du savon. En milieu acide (H₂SO₄), on obtient du glycérol et des acides gras libres.', 1),
  ('20000000-0000-0000-0000-000000000016', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Identifiez la structure d''un acide gras SATURÉ :', null, 'L''acide palmitique (C16:0) est un acide gras saturé : chaîne linéaire sans double liaison, formule CH₃–(CH₂)₁₄–COOH. Il est solide à température ambiante. Les autres structures montrent des doubles liaisons (représentées par des doubles traits colorés).', 1),
  ('20000000-0000-0000-0000-000000000017', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Quelle structure correspond à l''acide oléique (C18:1 Δ9) ?', null, 'L''acide oléique (C18:1 Δ9) possède une seule double liaison en position 9 (représentée en bleu). Il est liquide à température ambiante, présent en grande quantité dans l''huile d''olive. Formule : CH₃–(CH₂)₇–CH=CH–(CH₂)₇–COOH.', 1),
  ('20000000-0000-0000-0000-000000000018', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Identifiez la structure d''un triglycéride (triacylglycérol) :', null, 'Un triglycéride (αβα'' triacylglycérol) possède les 3 fonctions alcool du glycérol estérifiées par 3 acides gras (R1, R2, R3). Si R1=R2=R3 : triglycéride homogène ; si différents : triglycéride hétérogène. Ce sont les lipides de réserve énergétique.', 1),
  ('20000000-0000-0000-0000-000000000019', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Quel schéma représente un monoglycéride ?', null, 'Un monoglycéride (α-monoacylglycérol) résulte de l''estérification d''une seule des 3 fonctions alcool du glycérol par un acide gras. Les 2 autres fonctions –OH restent libres. Il existe aussi des β-monoglycérides.', 1),
  ('20000000-0000-0000-0000-000000000020', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Quelle structure correspond à un glycérophospholipide ?', null, 'Un glycérophospholipide est formé d''un glycérol estérifié par 2 AG (en Cα et Cβ) et par l''acide phosphorique (en Cα'') lié à un groupement X. Il possède un pôle hydrophobe (chaînes AG) et un pôle hydrophile (tête phosphate+X), ce qui lui confère son caractère amphiphile.', 1),
  ('20000000-0000-0000-0000-000000000021', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Identifiez la structure de la sphingomyéline :', null, 'La sphingomyéline est formée d''une sphingosine liée à un AG par une liaison amide (–NH–CO–R), avec un groupement phosphocholine en tête. Elle est abondante dans les neurones (gaine de myéline). La liaison amide la distingue des glycérophospholipides (liaison ester).', 1),
  ('20000000-0000-0000-0000-000000000022', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Quelle structure représente une cire comme le palmitate de cétyle ?', null, 'Une cire est un ester d''un acide gras et d''un alcool aliphatique à longue chaîne carbonée. Le palmitate de cétyle (C₃₀H₆₁–O–CO–C₁₅H₃₁) constitue 92% du blanc de baleine. Les cires sont des lipides de revêtement (cires végétales, cires d''abeilles, cires d''insectes).', 1),
  ('20000000-0000-0000-0000-000000000023', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Un céramide est formé par :', null, 'Un céramide résulte de la fixation d''un acide gras sur la fonction amine de la sphingosine par une liaison amide. C''est le précurseur commun des sphingolipides : sphingomyélines (+ phosphocholine), cérébrosides (+ ose), gangliosides (+ oligosaccharides).', 1),
  ('20000000-0000-0000-0000-000000000024', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Identifiez le galactocérébroside :', null, 'Le galactocérébroside est formé d''un céramide lié à une molécule de D-galactose par une liaison β-glycosidique en position 1 de la sphingosine (β D-galactosyl(1;1) céramide). C''est un lipide non phosphoré, présent dans le tissu nerveux.', 1),
  ('20000000-0000-0000-0000-000000000025', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'L''acide arachidonique (C20:4 Δ5,8,11,14) possède :', null, 'L''acide arachidonique (C20:4 Δ5,8,11,14) est un acide gras polyinsaturé avec 4 doubles liaisons en positions 5, 8, 11 et 14. C''est un acide gras essentiel oméga-6, précurseur des prostaglandines et des leucotriènes.', 1),
  ('20000000-0000-0000-0000-000000000026', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Quelle structure représente la phosphatidylcholine (lécithine) ?', null, 'La lécithine (phosphatidylcholine) est un glycérophospholipide avec X = choline [HOCH₂CH₂–N⁺(CH₃)₃]. Elle est très répandue dans les membranes des cellules animales et peu présente chez les bactéries. Son caractère amphiphile lui permet de s''organiser en bicouche lipidique.', 1),
  ('20000000-0000-0000-0000-000000000027', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Quel acide gras possède seulement 4 atomes de carbone ?', null, 'L''acide butyrique (CH₃–CH₂–CH₂–COOH) est le plus petit acide gras constitutif des lipides avec 4 atomes de carbone. Il est présent dans le beurre et donne à ce dernier son odeur caractéristique. Les AG des lipides commencent par l''acide butyrique.', 1),
  ('20000000-0000-0000-0000-000000000028', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Identifiez l''acide stéarique (C18:0) :', null, 'L''acide stéarique (CH₃–(CH₂)₁₆–COOH) est un acide gras saturé à 18 carbones (C18:0). Avec son point de fusion élevé, il est solide à température ambiante. Ne pas confondre avec l''acide oléique C18:1 (qui a une double liaison) ou l''acide linoléique C18:2.', 1),
  ('20000000-0000-0000-0000-000000000029', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Quelle structure montre un diglycéride (diacylglycérol) ?', null, 'Un diglycéride (αβ ou αα'' diacylglycérol) résulte de l''estérification de deux fonctions alcool du glycérol par 2 acides gras. La troisième fonction –OH reste libre. Si R1=R2 : diglycéride homogène ; si R1≠R2 : diglycéride hétérogène.', 1),
  ('20000000-0000-0000-0000-000000000030', '22222222-3333-4444-5555-000000000002', 'qcm_single', 'Identifiez l''acide linoléique (C18:2 Δ9,12), un acide gras essentiel oméga-6 :', null, 'L''acide linoléique (C18:2 Δ9,12) est un acide gras polyinsaturé avec 2 doubles liaisons en positions 9 et 12. C''est un acide gras essentiel (non synthétisé par l''organisme, doit être apporté par l''alimentation). Il appartient à la famille oméga-6.', 1),
  ('20000000-0000-0000-0000-000000000031', '22222222-3333-4444-5555-000000000003', 'qcm_single', 'Les cires sont classées parmi les lipides :', null, 'Les cires sont des lipides simples (homolipides) : leur hydrolyse ne libère que des acides gras et des alcools aliphatiques à longue chaîne. Elles constituent les lipides de revêtement (cires végétales, cutine, cire d''abeille, blanc de baleine).', 1),
  ('20000000-0000-0000-0000-000000000032', '22222222-3333-4444-5555-000000000003', 'qcm_single', 'Quel type de lipide constitue PRINCIPALEMENT les membranes cellulaires ?', null, 'Les membranes cellulaires sont principalement constituées de phospholipides (glycérophospholipides, sphingomyélines), de galactolipides et de sulfolipides. Leur caractère amphiphile permet la formation de la bicouche lipidique. Les triglycérides sont les lipides de réserve énergétique.', 1),
  ('20000000-0000-0000-0000-000000000033', '22222222-3333-4444-5555-000000000003', 'qcm_single', 'À partir de combien d''atomes de carbone un acide gras devient-il insoluble dans l''eau ?', null, 'Dès que la chaîne carbonée devient supérieure à 8 atomes de carbone, l''acide gras devient insoluble dans l''eau. Par contre, les acides gras sous forme de sels alcalins (savons) sont solubles dans l''eau, car la tête polaire –COO⁻ permet la solubilisation.', 1),
  ('20000000-0000-0000-0000-000000000034', '22222222-3333-4444-5555-000000000003', 'qcm_single', 'Le rancissement des corps gras est dû à :', null, 'Le rancissement est causé par l''oxydation spontanée des acides gras (surtout insaturés) à l''air libre. Il entraîne une odeur forte et une saveur âcre désagréables. Les doubles liaisons sont particulièrement sensibles à l''oxydation. Les antioxydants (vitamine E) protègent contre ce phénomène.', 1),
  ('20000000-0000-0000-0000-000000000035', '22222222-3333-4444-5555-000000000003', 'qcm_single', 'La réaction de transestérification (alcoolyse) d''un triglycéride avec du méthanol produit :', null, 'La transestérification (alcoolyse) d''un triglycéride avec du méthanol produit des esters méthyliques d''acides gras (EMAG) + du glycérol. Cette réaction est utilisée en chromatographie en phase gazeuse pour identifier les AG. Les EMAG sont aussi produits pour le biodiesel.', 1),
  ('20000000-0000-0000-0000-000000000036', '22222222-3333-4444-5555-000000000003', 'qcm_single', 'En chromatographie en phase gazeuse des acides gras, lequel sort le plus LENTEMENT ?', null, 'En chromatographie en phase gazeuse, les AG sortent d''autant plus lentement qu''ils ont une longue chaîne d''atomes de carbone. À nombre égal d''atomes de C, ce sont les AG insaturés qui sortent le plus lentement. La surface des pics est proportionnelle à la quantité de l''AG.', 1),
  ('20000000-0000-0000-0000-000000000037', '22222222-3333-4444-5555-000000000003', 'qcm_single', 'Les cardiolipides (diphosphatidyl glycérol) sont caractéristiques de :', null, 'Les cardiolipides (diphosphatidylglycérol, X = glycérol) sont caractéristiques des membranes bactériennes et des membranes des mitochondries cardiaques. Leur structure particulière avec 4 chaînes d''acides gras est essentielle au fonctionnement de la chaîne respiratoire.', 1),
  ('20000000-0000-0000-0000-000000000038', '22222222-3333-4444-5555-000000000003', 'qcm_single', 'Les vitamines liposolubles sont des lipides de la classe des :', null, 'Les vitamines liposolubles (A, D, E, K) appartiennent à la classe des terpènes (lipides polyisopréniques). Elles sont solubles dans les graisses et les huiles, et insolubles dans l''eau. Elles se stockent dans les tissus adipeux et hépatiques.', 1),
  ('20000000-0000-0000-0000-000000000039', '22222222-3333-4444-5555-000000000003', 'qcm_single', 'Les plasmalogènes se trouvent principalement dans :', null, 'Les plasmalogènes sont des glycérophospholipides particuliers (avec une liaison alcénoxy en Cα à la place de la liaison ester). Ils sont présents dans le tissu nerveux et musculaire et dans le plasma sanguin. Ils contiennent souvent de l''éthanolamine et de l''acide arachidonique.', 1),
  ('20000000-0000-0000-0000-000000000040', '22222222-3333-4444-5555-000000000003', 'qcm_single', 'Les carotènes et lycopènes sont des terpènes classés parmi les :', null, 'Les carotènes (pigments jaunes-orangés de la carotte) et les lycopènes (pigments rouges de la tomate) sont des pigments caroténoïdes, des terpènes très riches en doubles liaisons conjuguées. Ces doubles liaisons conjuguées absorbent la lumière visible, leur donnant leurs couleurs caractéristiques.', 1),
  ('30000000-0000-0000-0000-000000000001', '33333333-4444-5555-6666-000000000001', 'text_answer', 'Quel organe pompe le sang dans le corps ?', null, 'Le cur.', 1),
  ('30000000-0000-0000-0000-000000000002', '33333333-4444-5555-6666-000000000001', 'text_answer', 'Combien de cavités possède le cur ?', null, '4 cavités.', 1),
  ('30000000-0000-0000-0000-000000000003', '33333333-4444-5555-6666-000000000001', 'text_answer', 'Comment sappellent les deux cavités supérieures ?', null, 'Les oreillettes.', 1),
  ('30000000-0000-0000-0000-000000000004', '33333333-4444-5555-6666-000000000001', 'text_answer', 'Comment sappellent les deux cavités inférieures ?', null, 'Les ventricules.', 1),
  ('30000000-0000-0000-0000-000000000005', '33333333-4444-5555-6666-000000000001', 'text_answer', 'Quel vaisseau transporte le sang du cur vers les organes ?', null, 'Les artères.', 1),
  ('30000000-0000-0000-0000-000000000006', '33333333-4444-5555-6666-000000000001', 'text_answer', 'Quel vaisseau ramène le sang vers le cur ?', null, 'Les veines.', 1),
  ('30000000-0000-0000-0000-000000000007', '33333333-4444-5555-6666-000000000001', 'text_answer', 'Quel est le rôle principal du système cardiovasculaire ?', null, 'Transporter loxygène, les nutriments et éliminer les déchets.', 1),
  ('30000000-0000-0000-0000-000000000008', '33333333-4444-5555-6666-000000000001', 'text_answer', 'Quelle valve sépare loreillette gauche du ventricule gauche ?', null, 'La valve mitrale.', 1),
  ('30000000-0000-0000-0000-000000000009', '33333333-4444-5555-6666-000000000001', 'text_answer', 'Quelle est la plus grande artère du corps ?', null, 'Laorte.', 1),
  ('30000000-0000-0000-0000-000000000010', '33333333-4444-5555-6666-000000000001', 'text_answer', 'Quel côté du cur contient du sang riche en oxygène ?', null, 'Le côté gauche.', 1),
  ('31000000-0000-0000-0000-000000000001', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quel est le rôle principal du cur ?', null, 'Le cur agit comme une pompe qui propulse le sang dans tout lorganisme.', 1),
  ('31000000-0000-0000-0000-000000000002', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quelles sont les deux circulations sanguines ?', null, 'La circulation pulmonaire La circulation systémique', 1),
  ('31000000-0000-0000-0000-000000000003', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quelle est la différence entre systole et diastole ?', null, 'Systole : contraction du cur Diastole : relâchement et remplissage du cur', 1),
  ('31000000-0000-0000-0000-000000000004', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Définir le débit cardiaque.', null, 'Le débit cardiaque est le volume de sang éjecté par le cur en une minute.', 1),
  ('31000000-0000-0000-0000-000000000005', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Donner la formule du débit cardiaque.', null, 'DC=FC×VESDC = FC \times VESDC=FC×VES', 1),
  ('31000000-0000-0000-0000-000000000006', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quest-ce que la fréquence cardiaque ?', null, 'Cest le nombre de battements du cur par minute.', 1),
  ('31000000-0000-0000-0000-000000000007', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quest-ce que le volume déjection systolique (VES) ?', null, 'Cest la quantité de sang éjectée par un ventricule à chaque contraction.', 1),
  ('31000000-0000-0000-0000-000000000008', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quelle est la valeur normale de la fréquence cardiaque chez ladulte ?', null, 'Entre 60 et 100 battements par minute.', 1),
  ('31000000-0000-0000-0000-000000000009', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Définir la pression artérielle.', null, 'Force exercée par le sang sur la paroi des artères.', 1),
  ('31000000-0000-0000-0000-000000000010', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quelle est la pression artérielle normale ?', null, 'Environ 120/80 mmHg.', 1),
  ('31000000-0000-0000-0000-000000000011', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quest-ce que la pression systolique ?', null, 'La pression maximale lors de la contraction ventriculaire.', 1),
  ('31000000-0000-0000-0000-000000000012', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quest-ce que la pression diastolique ?', null, 'La pression minimale lors du relâchement du cur.', 1),
  ('31000000-0000-0000-0000-000000000013', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quel est le rôle des valves cardiaques ?', null, 'Empêcher le reflux du sang.', 1),
  ('31000000-0000-0000-0000-000000000014', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Combien de cavités possède le cur ?', null, 'Le cur possède 4 cavités : 2 oreillettes 2 ventricules', 1),
  ('31000000-0000-0000-0000-000000000015', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quel est le rôle du ventricule gauche ?', null, 'Il envoie le sang oxygéné dans tout lorganisme.', 1),
  ('31000000-0000-0000-0000-000000000016', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quel est le rôle du ventricule droit ?', null, 'Il envoie le sang vers les poumons.', 1),
  ('31000000-0000-0000-0000-000000000017', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Définir le retour veineux.', null, 'Quantité de sang revenant au cur par les veines.', 1),
  ('31000000-0000-0000-0000-000000000018', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quest-ce que lECG ?', null, 'Enregistrement de lactivité électrique du cur.', 1),
  ('31000000-0000-0000-0000-000000000019', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Que représente londe P sur lECG ?', null, 'La dépolarisation des oreillettes.', 1),
  ('31000000-0000-0000-0000-000000000020', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Que représente le complexe QRS ?', null, 'La dépolarisation des ventricules.', 1),
  ('31000000-0000-0000-0000-000000000021', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Que représente londe T ?', null, 'La repolarisation ventriculaire.', 1),
  ('31000000-0000-0000-0000-000000000022', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quel est le pacemaker naturel du cur ?', null, 'Le nud sinusal.', 1),
  ('31000000-0000-0000-0000-000000000023', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quel est le rôle du nud auriculo-ventriculaire ?', null, 'Ralentir la conduction électrique entre oreillettes et ventricules.', 1),
  ('31000000-0000-0000-0000-000000000024', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Définir la vasodilatation.', null, 'Augmentation du diamètre des vaisseaux sanguins.', 1),
  ('31000000-0000-0000-0000-000000000025', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Définir la vasoconstriction.', null, 'Diminution du diamètre des vaisseaux sanguins.', 1),
  ('31000000-0000-0000-0000-000000000026', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quest-ce que la précharge ?', null, 'Étirement des fibres cardiaques avant la contraction.', 1),
  ('31000000-0000-0000-0000-000000000027', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quest-ce que la postcharge ?', null, 'Résistance contre laquelle le ventricule éjecte le sang.', 1),
  ('31000000-0000-0000-0000-000000000028', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Définir la contractilité.', null, 'Capacité du muscle cardiaque à se contracter.', 1),
  ('31000000-0000-0000-0000-000000000029', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quest-ce que la fraction déjection ?', null, 'Pourcentage de sang éjecté par le ventricule gauche à chaque systole.', 1),
  ('31000000-0000-0000-0000-000000000030', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Définir la loi de Frank-Starling.', null, 'Plus le remplissage du cur augmente, plus la force de contraction augmente.', 1),
  ('31000000-0000-0000-0000-000000000031', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quest-ce que le pouls ?', null, 'Expansion rythmique des artères due à léjection sanguine.', 1),
  ('31000000-0000-0000-0000-000000000032', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quel est le rôle des artères ?', null, 'Transporter le sang du cur vers les organes.', 1),
  ('31000000-0000-0000-0000-000000000033', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quel est le rôle des veines ?', null, 'Ramener le sang vers le cur.', 1),
  ('31000000-0000-0000-0000-000000000034', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quel est le rôle des capillaires ?', null, 'Permettre les échanges entre le sang et les tissus.', 1),
  ('31000000-0000-0000-0000-000000000035', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quest-ce que lhémodynamique ?', null, 'Étude des mouvements du sang dans le système cardiovasculaire.', 1),
  ('31000000-0000-0000-0000-000000000036', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quest-ce quun barorécepteur ?', null, 'Récepteur sensible aux variations de pression artérielle.', 1),
  ('31000000-0000-0000-0000-000000000037', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quel système augmente la fréquence cardiaque ?', null, 'Le système nerveux sympathique.', 1),
  ('31000000-0000-0000-0000-000000000038', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Quel système diminue la fréquence cardiaque ?', null, 'Le système parasympathique.', 1),
  ('31000000-0000-0000-0000-000000000039', '33333333-4444-5555-6666-000000000002', 'text_answer', 'Où se trouve le sang oxygéné dans le cur ?', null, 'Dans les cavités gauches.', 1),
